package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    // Use reflection to get the constructor since LineItem class is incomplete or inaccessible
    var constructor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    LineItem lineItem = constructor.newInstance("itemName", 2, 1000L, "USD");

    String actualCurrencyCode = lineItem.getCurrencyCode();
    assertEquals("USD", actualCurrencyCode);
  }
}
